ig = np.array(initial_grid)


def compute_score(gt, pred):
    pred = np.maximum(pred, FLOOR)
    pred = pred / pred.sum(axis=2, keepdims=True)
    te = wkl = 0
    for y in range(40):
        for x in range(40):
            p = gt[y, x]; q = pred[y, x]
            h = -np.sum(p * np.log(p + 1e-10))
            if h > 0.001:
                kl = np.sum(p * np.log((p + 1e-10) / (q + 1e-10)))
                wkl += h * kl; te += h
    wkl = wkl / te if te > 0 else 0
    return 100 * np.exp(-3 * wkl), wkl


# Test 1: Gaussian smoothing on global priors
print("=== Gaussian smoothing on GLOBAL PRIORS ===")
for sigma in [0.0, 0.3, 0.5, 0.7, 1.0, 1.5]:
    scores = []
    for s in range(5):
        gt = np.array(gt_data[f"seed_{s}"])
        pred = np.zeros((40, 40, 6))
        for y in range(40):
            for x in range(40):
                t = int(ig[y, x])
                pred[y, x] = EMPIRICAL.get(t, np.ones(6) / 6)

        if sigma > 0:
            ocean_mask = ig == 10
            for c in range(6):
                layer = pred[:, :, c].copy()
                smoothed = gaussian_filter(layer, sigma=sigma)
                smoothed[ocean_mask] = pred[ocean_mask, c]
                pred[:, :, c] = smoothed
            pred = np.maximum(pred, FLOOR)
            pred = pred / pred.sum(axis=2, keepdims=True)

        score, wkl = compute_score(gt, pred)
        scores.append(score)
    print(f"  sigma={sigma:.1f}: avg={np.mean(scores):.2f} ({min(scores):.2f}-{max(scores):.2f})")

# Test 2: Smoothing on simulated observations
print("\n=== Gaussian smoothing on OBS (n=1, alpha=0.1, pw=0.5) ===")
np.random.seed(42)
for sigma in [0.0, 0.3, 0.5, 0.7, 1.0]:
    scores = []
    for s in range(5):
        gt = np.array(gt_data[f"seed_{s}"])
        pred = np.zeros((40, 40, 6))
        for y in range(40):
            for x in range(40):
                t = int(ig[y, x])
                p_true = gt[y, x]
                if t == 10:
                    pred[y, x] = EMPIRICAL[10]
                else:
                    sample = np.random.choice(6, p=p_true)
                    obs = np.zeros(6)
                    obs[sample] = 1
                    posterior = (obs + 0.1) / (1 + 0.6)
                    prior = EMPIRICAL.get(t, np.ones(6) / 6)
                    pred[y, x] = 0.5 * posterior + 0.5 * prior

        if sigma > 0:
            ocean_mask = ig == 10
            for c in range(6):
                layer = pred[:, :, c].copy()
                smoothed = gaussian_filter(layer, sigma=sigma)
                smoothed[ocean_mask] = pred[ocean_mask, c]
                pred[:, :, c] = smoothed
            pred = np.maximum(pred, FLOOR)
            pred = pred / pred.sum(axis=2, keepdims=True)

        score, wkl = compute_score(gt, pred)
        scores.append(score)
    print(f"  sigma={sigma:.1f}: avg={np.mean(scores):.2f}")

# Test 3: Ground truth itself smoothed — does GT have spatial correlation?
print("\n=== Spatial correlation in GROUND TRUTH ===")
for s in range(1):
    gt = np.array(gt_data[f"seed_{s}"])
    # Check: do neighboring cells have similar distributions?
    cors = []
    for y in range(1, 39):
        for x in range(1, 39):
            if ig[y, x] == 10:
                continue
            p = gt[y, x]
            for dy, dx in [(-1,0), (1,0), (0,-1), (0,1)]:
                ny, nx = y+dy, x+dx
                if ig[ny, nx] == 10:
                    continue
                q = gt[ny, nx]
                # Cosine similarity
                cos = np.dot(p, q) / (np.linalg.norm(p) * np.linalg.norm(q) + 1e-10)
                cors.append(cos)
    print(f"  Seed {s}: avg neighbor cosine similarity = {np.mean(cors):.4f}")
    print(f"  (1.0 = identical, 0.0 = orthogonal)")
    # What about cells of same initial type?
    for t_name, t_val in [("plains", 11), ("forest", 4)]:
        same_type = []
        diff_type = []
        locs = list(zip(*np.where(ig == t_val)))
        for y, x in locs[:100]:
            p = gt[y, x]
            for dy, dx in [(-1,0), (1,0), (0,-1), (0,1)]:
                ny, nx = y+dy, x+dx
                if 0 <= ny < 40 and 0 <= nx < 40 and ig[ny, nx] != 10:
                    q = gt[ny, nx]
                    cos = np.dot(p, q) / (np.linalg.norm(p) * np.linalg.norm(q) + 1e-10)
                    if ig[ny, nx] == t_val:
                        same_type.append(cos)
                    else:
                        diff_type.append(cos)
        if same_type:
            print(f"  {t_name}-{t_name} neighbors: cos={np.mean(same_type):.4f} (n={len(same_type)})")
        if diff_type:
            print(f"  {t_name}-other neighbors: cos={np.mean(diff_type):.4f} (n={len(diff_type)})")
